var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"검은 범람 발생 14시간 경과","JPN":"黒い氾濫の発生から14時間経過","ENG":"14 hours since the Black Flood onset","TWN":"黑色洪災發生14小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"섬 주민들을 흔쾌히 태워주셔서 감사해요.","JPN":"快くの島の住民たちを乗せてくださって、ありがとうございます。","ENG":"Thank you for taking in our islanders without hesitation.","TWN":"謝謝妳毫不猶豫地接納島上的居民。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그러니까…….","JPN":"ええと……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"메리 크루.","JPN":"メリー・クルー。","ENG":"Mary Crew.","TWN":"瑪麗·克盧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"지금은 메리 크루라고 불러주는 게 좋겠구나.","JPN":"今はメリー・クルーと呼んでちょうだい。","ENG":"For now, it's best if you call me Mary Crew.","TWN":"現在就叫我瑪麗·克盧吧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리 해적단의 메리 리드는… 이미 바닷속에 잠들어 있으니 말이다.","JPN":"エイバリー海賊団のメリー・リードは……海の底で眠りについたからね。","ENG":"Mary Read of the Avery Pirates... is already resting beneath the sea.","TWN":"艾維利海盜團的瑪麗·里德……已經沉入海底了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그리고 다른 아이들에겐…….","JPN":"それから、他の子たちには……","ENG":"And for the others...","TWN":"至於其他孩子們……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"네. 알고 있어요.","JPN":"はい、わかっています。","ENG":"Yes. I know.","TWN":"嗯，我知道。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"조심하도록 할게요.","JPN":"気をつけます。","ENG":"I'll be careful.","TWN":"我會小心的。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"도와줘서 고마워, 아줌마.","JPN":"助けてくれてありがとう、おばさん。","ENG":"Thanks for helping, Auntie Mary.","TWN":"謝謝妳幫忙，阿姨。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후후, 뛰어난 사냥꾼을 데려온 덕분이란다.","JPN":"ふふ、優秀な狩人を連れてきた甲斐があったね。","ENG":"Fufu, you brought quite the impressive hunter with you.","TWN":"呵呵，多虧我帶了一位出色的獵手。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"망설임 없이 사냥감을 향해 송곳니를 꽂는 그 움직임.","JPN":"迷わず獲物に向かって牙を突き刺すあの動き。","ENG":"The way she sank her fangs into her prey without a hint of hesitation...","TWN":"那毫不猶豫撲咬獵物的動作，"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"자신이 뭐를 위해 싸우는지 잘 아는 것 같은 모습이었단다.","JPN":"自分が何のために戦っているのか、よくわかっている動きだった。","ENG":"She fights knowing exactly what she's fighting for.","TWN":"讓人覺得她很清楚自己為了什麼而戰。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐를 위해서… 싸우는 지?","JPN":"何のために……戦っているのか？","ENG":"What she's... fighting for?","TWN":"為了什麼……而戰？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래. 너에게 한 번쯤은 소개해 주고 싶을 정도로 목적이 확실했지.","JPN":"そう。一度あなたに紹介してあげたいと思ったほど、目的がはっきりしていたわ。","ENG":"Yes. Clear enough that I'd introduce her to you at least once.","TWN":"是啊。她的目標明確到我好想介紹給妳。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"네 소식은 아주 잘 들려오더구나.","JPN":"あなたの近況は、よく耳に入ってきていたよ。","ENG":"I've heard plenty about you.","TWN":"我一直都有收到妳的消息。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"자유를 위해… 관리국을 뒤엎으려 했다지?","JPN":"自由のために……管理局を倒そうとしたのね？","ENG":"You tried to topple the Administration... all for freedom, I hear?","TWN":"妳為了自由……想要推翻管理局，對吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아직도 그 생각은 변함이 없니?","JPN":"その考えは、今も変わらない？","ENG":"Do you still feel the same way?","TWN":"妳還沒改變那個想法嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"하지만 키이라.","JPN":"でもね、キーラさん。","ENG":"But Kiera.","TWN":"但是琪伊拉，"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"때론 사람은 상식적으로 이해할 수 없는 행동을 하기도 해요.","JPN":"時に人は、常識では理解できない行動をしたりもします。","ENG":"Sometimes people act in ways that defy reason.","TWN":"有時候人也會做出無法用常理解釋的行動。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"예를 들면, 내가 평생을 바쳐 번 돈으로 산 집,","JPN":"例えば、自分が一生稼いだお金で買った家、","ENG":"Like the home I worked my whole life to build,","TWN":"例如，用一生積蓄買下的房子、"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"내 유년 시절을 바친 고향,","JPN":"自分の幼い時代を捧げた故郷、","ENG":"the hometown that holds every memory of my childhood...","TWN":"寄託童年時光的故鄉、"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"혹은 그냥 이곳의 분위기, 냄새, 사람들…… 그런 것들이 좋아서 자유를 내던지는 사람들이 많죠.","JPN":"あるいはただここの雰囲気、匂い、人々……そんなものが好きで自由を犠牲にする人もいるのです。","ENG":"or even just the feel of this place, its scent, its voices... Some people give up their freedom for things like that.","TWN":"又或者只是不知為何喜歡這裡的氛圍、味道、以及這裡的人們……也有很多因為這些理由而放棄自由的人。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"20년 전, 갑작스레 일어난 검은 범람에 휘말린 우리 섬을 구해준…….","JPN":"20年前、突然と発生した黒い氾濫に巻き込まれた私たちの島を助けてくれた……","ENG":"Just like the Avery Pirates did...","TWN":"20年前，拯救這座被突如其來的黑色洪災襲擊的島嶼的……"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"에이버리 해적단처럼 말이에요.","JPN":"エイバリー海賊団のように。","ENG":"when they saved our island twenty years ago, during the Black Flood.","TWN":"就是艾維利海盜團。"},"stage":{"bg":"FRONTBAY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"잘… 모르겠어.","JPN":"よく……わかんない。","ENG":"I... still don't really know.","TWN":"我……不知道。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"모르겠다…라.","JPN":"わからない……ね。","ENG":"You don't know... huh?","TWN":"不知道……啊。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그럼 하나만 물어볼게.","JPN":"じゃあ、1つだけ聞くわ。","ENG":"Then let me ask you one thing.","TWN":"那我問你一個問題。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"대해적이 되겠다는 너의 꿈은… 아직 남아있니?","JPN":"大海賊になるというあなたの夢は……まだ残っている？","ENG":"Is your dream of becoming a great pirate... still there?","TWN":"你成為大海盜的夢想……還在嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"후후, 그리고 키이라 씨를 보다 보면 그때 봤던 부함장님이 생각나요.","JPN":"ふふ、それにキーラさんを見ていると、あの時お会いした副艦長が思い出されるわ。","ENG":"Fufu... And when I look at Kiera, she reminds me of the first mate I met back then.","TWN":"呵呵，每次看著妳，都會讓我想起那時看到的副船長。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그분도 당신과 비슷하지만 다른 말씀을 하셨거든요.","JPN":"あの方も、あなたの言葉と近いけれど、少し違うことをおっしゃっていました。","ENG":"She said something a little like what you said but in her own way.","TWN":"她也說過一句有點類似但又不太一樣的話。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"사람의 목숨을, 자신의 자유를 포기하면서까지 지켜야 할 것이 있는 법이라고.","JPN":"人の命や自分の自由を放棄してでも、守らなければいけないものはあるんだって。","ENG":"That there are things worth protecting even if it costs your freedom... even if it costs your life.","TWN":"人有時候會為了某些東西，付出自己的生命與自由去守護。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리 해적단의 부함장이 그런 말을 했대.","JPN":"エイバリー海賊団の副艦長が、こういうことを言ってたらしいんだ。","ENG":"The first mate of the Avery Pirates said that.","TWN":"艾維利海盜團的副船長曾說過這句話。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"사람의 목숨을, 자신의 자유를 포기하면서까지 지켜야 할 것이 있는 법이라고.","JPN":"人の命や自分の自由を放棄してでも、守らなければいけないものはあるんだって。","ENG":"That there are things worth protecting even if it costs your freedom... even if it costs your life.","TWN":"人有時候會為了某些東西，付出自己的生命與自由去守護。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 말의 의미를 아직 잘 모르겠어. 하지만…….","JPN":"その言葉の意味は、まだよくわからない。でも……","ENG":"I still don't fully understand what she meant. But...","TWN":"我還是不太懂那句話的意思，但……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 그 사람의 마음을, 생각을 이해한다면…….","JPN":"あたしがその人の気持ちを、考えを理解できたら……","ENG":"If I could understand what she felt, what she believed...","TWN":"如果我能理解那位的心情、想法……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"지금보다는 더 그럴듯한 소리로 들리지 않을까?","JPN":"今よりはもう少し、それっぽく聞こえるんじゃないかな。","ENG":"Maybe those words would sound more convincing coming from my own mouth.","TWN":"現在聽起來，會不會更有道理一些呢？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"대해적이 된다는 말 말이야.","JPN":"大海賊になるって言葉がさ。","ENG":"Especially the part about becoming a great pirate.","TWN":"妳說想成為大海盜的事。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그것마저 모르겠다고 했으면 호되게 혼낼 생각이었는데.","JPN":"それさえもわからないと言ったら、こっぴどく叱るつもりだったけど。","ENG":"If you had told me you didn't know that either, I was planning to scold you.","TWN":"如果妳連這都不明白，我可要好好教訓妳一頓呢。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아직 내가 기억하는 그 아이의 모습이 남아 있어 다행이구나.","JPN":"まだ記憶の中にいるあなたの面影が残っていてよかったわ。","ENG":"I'm glad the girl I remember is still in there.","TWN":"幸好妳還有我記憶中那個孩子的樣子。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래. 지금은 그거로 되었다.","JPN":"そう。今はそれで十分。","ENG":"Good. That's enough for now.","TWN":"嗯，現在變成那樣了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"...Yeah.","TWN":"……嗯。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"어떻게 들릴지 모르겠지만, 난 이 상황이 무척이나 즐겁단다.","JPN":"こう言ったらどう思うかわからないけど、私は今の状況がすごく楽しいの。","ENG":"This might sound strange, but... I'm actually enjoying this.","TWN":"我不知道妳的想法，但我對這情況感到很高興。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"오랜만에 느껴보는 짠 내, 침식체들의 울음소리, 처절한 사투…….","JPN":"久々に感じる塩辛い匂い、侵食体の鳴き声、壮絶な死闘……","ENG":"The salty air, the cries of the C.O.s, the desperate struggle...","TWN":"久違的緊張感、侵蝕體的嘶吼、慘烈的搏鬥……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"핏속에서 끓어오르는 혈기가 느껴지지 않니?","JPN":"体中の血が沸き立って来ない？","ENG":"Don't you feel your blood running through your body?","TWN":"妳難道感覺不到在血管中翻騰的熱血嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……이런 말 해서 미안한데.","JPN":"……こんなこと言って悪いけど。","ENG":"...Sorry to say this, but...","TWN":"……很抱歉對妳說這些。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"저 녀석이 저렇게 된 건… 아줌마 영향이 제일 컸을 것 같아.","JPN":"あいつがああなったのって……おばさんの影響が一番大きいと思う。","ENG":"I think you're the biggest reason that one... turned out like that.","TWN":"那傢伙會變成這樣……最大的原因，應該是受到阿姨的影響。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후후, 칭찬 고맙구나.","JPN":"ふふ、褒めてくれてありがとう。","ENG":"Fufu, thank you for the compliment.","TWN":"呵呵，謝謝妳的稱讚。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"다른 두 딸도 날 닮아서 아주 바르고 예쁘게 자랐거든.","JPN":"他の2人の娘も私に似て、とっても真っすぐで魅力的な子にに育ってくれたわ。","ENG":"My other two lovely daughters take after me as well.","TWN":"其他兩個女兒也像我一樣，正直又漂亮地長大了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"칭찬 아니거든.","JPN":"褒めてねえから。","ENG":"It wasn't a compliment.","TWN":"這不是稱讚啦。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어, 어, 어, 어머니. 그간 평안하셨는지요오?","JPN":"お、お、お、お母様。お変わりありませんでしたかああ？","ENG":"M-M-Mother! Have you been well?","TWN":"母、母、母、母親，您這段時間還好嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L48_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"나야 별 탈 없이 지냈단다.","JPN":"ええ、おかげさまでね。","ENG":"I've been fine, dear.","TWN":"我一切安好。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"탈리, 네가 사고치고 다닌 이야기는 가만히 앉아 있어도 다 들려오더구나.","JPN":"タリー、あなたが色々とやらかしてること、あえて耳を傾けなくても自然と流れてきてるわよ。","ENG":"Tallie, even when I sit still, I hear all about your mischief.","TWN":"塔莉，我就算坐著都能聽到你惹事的事。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"네 아버지의 금고를 털었다며?","JPN":"お父様の金庫を荒らしたんだって？","ENG":"I heard you even broke into your father's safe?","TWN":"妳偷了妳父親的保險箱？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"나는 유용하게 쓸 데가 있겠거니…하고 일부러 방치한 거였는데 말이다.","JPN":"あなたなりのいい使い道があるのでしょう……と思って、わざと放置していたのだけれど。","ENG":"I left it alone on purpose... thinking it might come in handy someday.","TWN":"我有其他用途……就故意放著沒管它。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"히이익! 어, 어머니 그건……!","JPN":"ひいいっ！　お、お母様、それは……！","ENG":"Eeek! M-Mother, that was...!","TWN":"嗚嗚嗚！母親，那個……！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"제 안에서 꿈틀거리는 해적의 혼이 그곳을 털라고 외쳤어요!","JPN":"私の中から湧き上がる海賊魂が、そこを荒らせと叫んだんです！","ENG":"The pirate spirit wriggling inside me told me to take it!","TWN":"都是我體內蠢蠢欲動的海盜魂叫我去偷的！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"포, 포기할 수 없는 거잖아요!","JPN":"あ、諦められないじゃないですか！","ENG":"I couldn't just abandon it!","TWN":"我、我放棄不了啊！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"해적의 약탈혼은!","JPN":"海賊の略奪欲って！","ENG":"It's the pirate's sacred instinct!","TWN":"海盜的掠奪魂……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"……뭐, 꽤 재밌었던 일이었으니 이번은 그냥 넘어가도록 하마.","JPN":"……まあ、かなり面白かったし、今回は見逃してあげるわ。","ENG":"...Well, it was amusing enough. I'll let it slide this time.","TWN":"……唔，那件事還挺有趣的，就先算了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"휘유…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"우리 사랑스러운 딸이 고작 용돈이 끊겨서 그러지 않았을 거라 믿어.","JPN":"私の愛娘だもの。単にお小遣いが足りないなんて理由で事を起こすわけないって信じてるわ。","ENG":"I trust my lovely daughter didn't do it just because her allowance got cut.","TWN":"我相信我們可愛的女兒，不會只是因為零用錢沒了才這麼做。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그, 그럼요! 어머니!","JPN":"も、もちろんです、お母様！","ENG":"O-of course not, Mother!","TWN":"當、當然啦！母親！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"하, 하하하…….","JPN":"あ、あはは……","ENG":"Hahaha...","TWN":"哈、哈哈哈……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"아줌마. 여기서는 마시멜로… 못 구워 먹어?","JPN":"おばさん。ここではマシュマロ……焼けない？","ENG":"Auntie Mary. Can't we... roast marshmallows here?","TWN":"阿姨，在這裡……不能烤棉花糖吃嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"음? 이 배에서 가장 뛰어난 사냥꾼이 왔구나.","JPN":"あら？　この船一の狩人が来たわね。","ENG":"Hmm? So the best hunter on this ship has arrived.","TWN":"嗯？最出色的獵手來這艘船啦。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"마시멜로는 요리사에게 부탁하면 맛있게 구워줄 거란다.","JPN":"マシュマロはシェフに頼んだら美味しく焼いてくれるわよ。","ENG":"Ask the cook. They'll roast them perfectly for you.","TWN":"把棉花糖交給廚師，他一定會幫妳烤得很好吃。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이 꼬마가…….","JPN":"このガキが……","ENG":"This kid...","TWN":"這小鬼……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래. 이 소녀가 바로 내가 말한 사냥꾼이란다.","JPN":"ええ。この少女が私の話した狩人よ。","ENG":"Yes. She's the hunter I mentioned.","TWN":"沒錯，她就是我說的那位獵手。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"오르카…라고 하더구나.","JPN":"名前はオルカ……と言ってたわね。","ENG":"Orca... was her name.","TWN":"他叫……奧爾卡。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"포식자에게 어울리는 이름이지?","JPN":"飽食者にぴったりな名前だと思わない？","ENG":"A fitting name for a predator, don't you think?","TWN":"很適合獵食者的名字吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이 사람은……?","JPN":"この人は……？","ENG":"Who is she...?","TWN":"這個人……？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"아줌마도, 이 사람도 포식자의 냄새가 나.","JPN":"おばさんも、この人も、飽食者の匂いがする。","ENG":"Both she and that person smell like predators.","TWN":"阿姨和他身上都有獵食者的氣息。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"포식자의… 냄새?","JPN":"飽食者の……匂い？","ENG":"Smell like... predators?","TWN":"獵食者的……氣息？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"응. 하지만… 아줌마랑은 다르게 네 냄새는 좀 달라.","JPN":"うん。でも……あなたのはおばさんの匂いとはちょっと違う。","ENG":"Yes. But... your scent is different from hers.","TWN":"嗯。但是……和阿姨的氣息有點不一樣。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카가 너에게선 망설임의 냄새가 배어있대.","JPN":"オルカが、あなたには迷いの匂いが染み込んでるって。","ENG":"Orca says you smell of hesitation.","TWN":"奧爾卡覺得妳帶著一點猶豫的氣息。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"망설임은 손톱을 무르게 하고, 이빨을 상하게 해.","JPN":"迷いは爪を弱らせて、牙を鈍くする。","ENG":"Hesitation softens claws and dulls teeth.","TWN":"猶豫會讓指甲變軟、牙齒受傷。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……넌 어떻게 흔들림 없이 싸울 수 있는 거지?","JPN":"……お前はなぜ、迷わずに戦える？","ENG":"...How do you fight without wavering?","TWN":"……妳戰鬥時怎麼能毫不動搖呢？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"나는 마시멜로를 나눠준 사람들을 지키기 위해 싸워.","JPN":"オルカはマシュマロをくれた人たちを守るために戦う。","ENG":"I fight to protect the ones who shared marshmallows with me.","TWN":"我為了守護那些分我棉花糖的人而戰。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그 따뜻함을, 그 포근함을 계속 간직하기 위해서 싸워.","JPN":"その温かさを、温もりを失わないために戦う。","ENG":"To keep that warmth and comfort safe.","TWN":"我為了守住那份溫暖、那份柔軟而戰。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"너는, 무엇을 위해 싸우는 거야?","JPN":"あなたは、何のために戦うの？","ENG":"What do you fight for?","TWN":"妳呢，妳為了什麼而戰？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아직 찌르는 것에 있어 망설임이 서려 있구나.","JPN":"まだ剣先に迷いがあるのね。","ENG":"You're still hesitating when it comes to striking.","TWN":"妳還是會在刺擊時有些遲疑呢。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그런 마음가짐으로 바다에 나가면 먹잇감이 되기 십상이란다.","JPN":"その程度の覚悟で海に出たら、エサになること間違いなしよ。","ENG":"If you go out to sea with that mindset, you'll end up as prey.","TWN":"如果抱著這種心態出海，很容易就會成為獵物。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리의 의지를 이어받아, 해적들에게 자유를 돌려줄 사람.","JPN":"エイバリーの意志を受け継ぎ、海賊に自由を取り戻してくれる人。","ENG":"Someone who will inherit Avery's will and return freedom to the pirates.","TWN":"我是要繼承艾維利的意志，把自由還給海盜的人。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ONLY_CHARADE_C_CRIMSON_CHAIN_2"},{"id":"L4_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"관리국에 빼앗긴 자유를 되찾아주는 사람이 대해적이야.","JPN":"管理局に奪われた自由を取り戻してくれる人が大海賊だ。","ENG":"A great pirate is someone who takes back the freedom the Administration stole.","TWN":"奪回被管理局奪走的自由之人，就是大海盜。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리의 의지라… 그렇군…….","JPN":"エイバリーの意志か……なるほど……","ENG":"Avery's will... I see...","TWN":"艾維利的意志啊……原來如此……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하나 충고하지.","JPN":"1つ忠告する。","ENG":"Let me give you some advice.","TWN":"我給妳一個忠告。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그런 식으로는 영원히 대해적이, 아니, 그럴듯한 해적조차 될 수 없을 거야.","JPN":"こんなやり方では永遠に大海賊、いや、海賊にすらなれないぞ。","ENG":"At this rate you'll never become a great pirate– No, not even a half-decent one.","TWN":"照妳現在的方式，永遠不可能成為大海盜。不，連像樣的海盜都當不了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"바다는 목적이 없는 얼간이를 집어삼키는 걸 좋아한다.","JPN":"海は目的を持たない愚か者を飲み込むことが好きなんだ。","ENG":"The sea loves swallowing fools without purpose.","TWN":"大海最喜歡吞噬沒有目標的蠢貨了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"지금 아가씨는… 바다가 집어삼키기 딱 좋은 먹잇감이로군.","JPN":"今のお嬢さんは……海が飲み込むにはちょうどいい獲物だな。","ENG":"And right now... you're the perfect meal.","TWN":"現在的妳……就是最適合被吞噬的獵物。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그렇다면, 네가 해적이 되면서까지 바다로 나온 이유는 뭐야?","JPN":"じゃあ、お前が海賊になってまで海に出た理由は何だ？","ENG":"Then what about you? Why'd you come out to sea and become a pirate?","TWN":"那麼，小姐成為海盜出海的理由是什麼？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나는 아까 말했다시피…….","JPN":"あたしはさっきも話したとおり……","ENG":"Like I said before...","TWN":"就像我剛剛說的……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그건 바다를 나와야 할 수 있는 게 아니잖아.","JPN":"それは海に出なきゃやれないことじゃないだろ。","ENG":"That's not something you need to go out to sea to accomplish.","TWN":"那不需要出海也能做到吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"해적이 되지 않아도 할 수 있는 거라고.","JPN":"海賊にならなくてもできることだ。","ENG":"You don't need to be a pirate to do that.","TWN":"就算不當海盜也做得到。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리 해적단이 여기까지 왔었다고?","JPN":"エイバリー海賊団がここまで来てたのか？","ENG":"The Avery Pirates came all the way out here?","TWN":"艾維利海盜團來過這裡？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그럼요. 아주 멋진 분들이었어요.","JPN":"ええ。とても素晴らしい方々でした。","ENG":"They did. They were truly wonderful people.","TWN":"當然，他們是非常帥氣的人。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"오늘만 살아가는 이들에게 내일을 보여주고 싶다는 말, 저는 아직도 기억하고 있거든요.","JPN":"今日だけを生きている者たちに明日を見せてあげたいという言葉、私はまだ忘れていません。","ENG":"The words, \\"To show tomorrow to those who only live in the moment,\\" I still remember clearly.","TWN":"我到現在都還記得想讓只活在今天的人也能看見明天這句話。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"오늘만 살아가는 이들에게… 내일을 보여주고 싶다…….","JPN":"今日だけを生きている者たちに……明日を見せてあげたい……","ENG":"To show tomorrow... to those who only live in the moment...","TWN":"讓只活在今天的人……看見明天……"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"후후, 그리고 키이라 씨를 보다 보면 그때 봤던 부함장님이 생각나요.","JPN":"ふふ、それにキーラさんを見ていると、あの時お会いした副艦長が思い出されるわ。","ENG":"Fufu... And when I look at Kiera, she reminds me of the first mate I met back then.","TWN":"呵呵，每次看著妳，都會讓我想起那時看到的副船長。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그분도 당신과 비슷하지만 다른 말씀을 하셨거든요.","JPN":"あの方も、あなたの言葉と近いけれど、少し違うことをおっしゃっていました。","ENG":"She said something a little like what you said but in her own way.","TWN":"她也說過一句有點類似但又不太一樣的話。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"사람의 목숨을, 자신의 자유를 포기하면서까지 지켜야 할 것이 있는 법이라고.","JPN":"人の命や自分の自由を放棄してでも、守らなければいけないものはあるんだって。","ENG":"That there are things worth protecting even if it costs your freedom... even if it costs your life.","TWN":"人有時候會為了某些東西，付出自己的生命與自由去守護。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"아무것도.","JPN":"何も。","ENG":"Nothing.","TWN":"任何事。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"난 어떤 것을 위해서도 싸우지 않아.","JPN":"あたしは何かのために、戦っていない。","ENG":"I don't fight for anything.","TWN":"我不為了什麼戰鬥。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"심지어 나 자신까지도… 말이야.","JPN":"まして自分のためになんて……","ENG":"Not even... for myself.","TWN":"甚至連我自己……都不例外。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"키이라…라고 했지?","JPN":"キーラ……だったよね。","ENG":"Kiera... right?","TWN":"妳叫琪伊拉……對吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"키이라는 누군가에게 마시멜로를 받아본 적이 없어?","JPN":"キーラは誰かにマシュマロをもらったこと、ある？","ENG":"Have you ever been given a marshmallow?","TWN":"琪伊拉，有人給過妳棉花糖嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"마시멜로?","JPN":"マシュマロ？","ENG":"A marshmallow?","TWN":"棉花糖？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"사람은 언제나 다른 사람들에게 마시멜로를 나눠줘.","JPN":"人はいつも、他の人にマシュマロをあげる。","ENG":"People always share marshmallows to others.","TWN":"大家總會和其他人分享棉花糖。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"키이라도 분명 있을 거야.","JPN":"キーラにもいるはず。","ENG":"You must have gotten some too, Kiera.","TWN":"妳一定也有吧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"키이라에게 마시멜로를 나눠준 사람이.","JPN":"キーラにマシュマロをくれた人が。","ENG":"Someone must have shared a marshmallow with you once.","TWN":"一定也有人給過給你棉花糖。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"지금 당장 떠올리지 않아도 괜찮아.","JPN":"今すぐ思い出さなくていい。","ENG":"It's okay if you can't think of them right now.","TWN":"現在馬上想不起來也沒關係。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"내가 마시멜로를 나눠준 사람을 지키기 위해 싸우듯.","JPN":"オルカがマシュマロをくれた人を守るために戦うように。","ENG":"Just as I fight to protect the ones who shared theirs with me...","TWN":"就像我為了守護給我棉花糖的人而戰一樣，"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"언젠가 키이라도 그런 사람들을 지키기 위해 싸우면 되니까.","JPN":"キーラもいつか、そんな人のために戦えばいいから。","ENG":"One day, you can fight to protect the people who shared theirs with you.","TWN":"總有一天，妳也會為了守護那些人而戰。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};